with inserted_events as (
  insert into public.health_events (title, group_name, badge, icon_key, output_title, urgency_base, short_description, summary, sort_order, is_active)
  values
    ('体检报告异常','报告与复诊','高频强痛点','FileText','异常报告整理 + 专科评估路径',88,'报告异常、指标异常、影像异常后的下一步','客户已经有报告或异常结果，最需要的不是泛泛科普，而是降低焦虑、整理资料、明确下一步找谁评估。',1,true),
    ('体检套餐选择','体检与筛查','高频触达入口','ClipboardList','基础体检 + 个性化加项配置',68,'不知道选基础、高端、癌筛还是专项体检','客户不知道套餐怎么选，顾问要避免“推贵套餐”的感觉，重点是解释基础项、加项和风险分层。',2,true),
    ('保险健康权益使用','权益与资源','权益激活','WalletCards','健康权益匹配 + 使用路径说明',74,'保单里的问诊、体检、绿通、二诊等怎么用','客户常常不知道保单里的健康服务什么时候能用，顾问需要把权益翻译成具体健康事件下的使用路径。',3,true),
    ('港深就医路径选择','权益与资源','港深路径','MapPinned','香港 / 深圳 / 内地路径判断',72,'香港、深圳私立、内地公立怎么选','客户不确定去哪看，本质是在比较效率、保险、费用、医生资源、语言和资料连续性。',4,true),
    ('企业主年度健康计划','长期关怀','高价值客户','Activity','高效体检 + 年度健康资产表',70,'企业主、高管的年度健康安排和家庭延展','企业主和高管客户通常不是没有资源，而是缺少高效、连续、少打扰的年度健康管理安排。',5,true),
    ('父母健康关怀','长期关怀','关系维护','HeartPulse','父母健康档案 + 年度检查提醒',62,'父母体检、慢病复查、癌筛和长期档案','父母健康是最自然、最不销售化的客户关怀入口，适合长期维护关系。',6,true),
    ('术后/病后复查','报告与复诊','持续服务','CalendarClock','复查计划 + 康复支持路径',76,'出院后、术后、病后复查和康复跟进','术后或病后客户容易在出院后断联，顾问可以用复查提醒、资料整理和权益匹配提供持续价值。',7,true)
  returning id, title
)
insert into public.event_playbooks (event_id, next_actions, checklist, resources, follow_up)
select
  e.id,
  p.next_actions::jsonb,
  p.checklist::jsonb,
  p.resources::jsonb,
  p.follow_up::jsonb
from inserted_events e
join (
  values
    ('体检报告异常','["先安抚客户，不要只凭单一指标下结论。","确认客户是否有完整报告、原始影像和既往同类检查结果。","把异常项整理成问题清单，再预约相关专科医生解读。","如果客户有明显症状、快速加重或医生已提示紧急处理，应优先安排就医。"]','["完整体检报告","异常项目截图","原始影像/电子影像","既往检查结果","既往病史","正在服用的药物","家族史"]','["专科医生评估","报告解读","二次意见","复查提醒","保险绿通/问诊权益"]','["当天：安抚并收集资料","1–3天：确认是否已预约专科","7天：跟进医生建议","30天：提醒复查或下一步安排"]'),
    ('体检套餐选择','["先确认客户年龄、性别、既往病史、家族史和最担心的问题。","把体检分成基础必选项、建议加项、暂不优先项目三类。","说明体检不是越贵越好，而是根据风险和阶段配置。","建议保留每年报告，方便做趋势比较，而不是只看单次结果。"]','["年龄/性别","过往体检报告","家族史","慢病史","症状或担忧","预算范围","是否需要港深跨境安排"]','["基础年度体检","癌筛加项","心脑血管风险评估","男女专项检查","体检后医生解读"]','["当天：确认客户需求和预算","3天：发送体检配置建议","体检后：收集报告并安排解读","每年：建立健康档案复盘"]'),
    ('保险健康权益使用','["先确认客户保单或会员服务中包含哪些健康权益。","把权益按场景分类：问诊、体检、绿通、二诊、陪诊、康复、心理/营养支持。","结合客户当前事件，说明哪些权益现在可用，哪些适合后续使用。","帮助客户准备申请或预约所需资料，并设置跟进节点。"]','["保单/会员权益说明","客户当前健康事件","既往报告","身份资料","就医城市","是否需要直付/理赔","客户可配合时间"]','["在线问诊","体检权益","门诊/住院绿通","二诊服务","陪诊服务","康复/营养/心理支持"]','["当天：确认可用权益","1–3天：协助发起预约或申请","就医后：跟进报告/医生建议","30天：提醒复查或权益后续使用"]'),
    ('港深就医路径选择','["先判断客户是体检规划、异常复诊，还是治疗/手术决策。","确认客户是否已有香港保险、指定网络、直付或理赔要求。","整理已有报告和影像，避免跨境重复检查。","根据紧急程度、预算、语言偏好和便利性，比较香港、深圳私立、内地公立路径。"]','["所在地","保险情况","已有报告/影像","问题类型","紧急程度","预算与时间","语言偏好","是否需要陪诊"]','["香港医生/医院路径","深圳私立医院路径","内地公立医院路径","跨境预约资料包","保险理赔资料清单"]','["当天：确认就医目标和资料","1–3天：比较路径并确认预约方向","就医前：检查资料是否齐全","就医后：跟进报告和复诊计划"]'),
    ('企业主年度健康计划','["先确认客户最担心的风险：心脑血管、肿瘤、代谢、睡眠压力或家族史。","设计半日/一日高效体检路径，并预留医生解读时间。","将检查结果沉淀为年度健康资产表，便于趋势比较。","把配偶、父母和关键家庭成员纳入下一阶段计划。"]','["工作强度","应酬/睡眠/运动情况","既往体检报告","家族史","慢病指标","最担心风险","可配合时间"]','["高效体检","心脑血管评估","肿瘤筛查","睡眠/压力评估","医生解读","家庭年度健康计划"]','["本周：确认健康优先级","1个月内：完成体检和医生解读","3个月：跟进异常指标","12个月：年度健康复盘"]'),
    ('父母健康关怀','["先从父母年龄、慢病、过往体检和家族史开始整理。","建立父母健康档案，记录每年关键指标变化。","提醒客户关注癌筛、心脑血管、骨密度、眼科、口腔等年龄相关问题。","有异常时优先整理资料，再预约专科医生评估。"]','["父母年龄","慢病史","用药清单","既往体检报告","家族史","最近不适症状","常去医院/医生"]','["父母年度体检","慢病复查提醒","癌筛加项","心脑血管评估","专科医生解读"]','["本周：建立父母健康档案","体检季：提醒年度检查","异常后：安排专科评估","每半年：关怀慢病指标"]'),
    ('术后/病后复查','["确认医生出院小结或复查建议中写明的复查时间和项目。","整理术后/病后资料，包括用药、检查、伤口或症状变化。","提醒客户按时复查，不自行停药或调整治疗方案。","如有康复、营养、心理或护理权益，可协助客户了解使用路径。"]','["出院小结","手术/治疗记录","复查建议","用药清单","近期症状变化","伤口/恢复情况","可用康复权益"]','["复查提醒","医生随访","康复护理","营养支持","心理支持","保险理赔资料"]','["出院后3天：确认恢复情况","1–2周：提醒复诊/拆线/复查","1个月：跟进医生建议","3个月：整理长期随访计划"]')
) as p(title, next_actions, checklist, resources, follow_up)
on e.title = p.title;

insert into public.script_templates (event_id, tone, template, is_active)
select e.id, s.tone, s.template, true
from public.health_events e
join (
  values
    ('体检报告异常','warm','先别太担心，体检报告里出现异常，并不代表一定就是严重问题。很多指标和影像结果都需要结合过往记录、症状和医生评估一起看。您可以先把完整报告、原始影像和以前的检查结果整理给我，我帮您先列一份就诊前资料清单和要问医生的问题，这样下一步会更清楚，也不用自己反复猜。'),
    ('体检报告异常','balanced','先不用只看一个指标就下结论，很多体检异常需要结合既往趋势、影像、症状和医生评估。您可以先把完整报告、原始影像、既往检查和用药情况整理给我，我帮您列出就诊前需要准备的问题清单，再由相关专科医生判断是否需要复查或进一步检查。'),
    ('体检报告异常','professional','建议先按资料完整性处理：1）提供完整体检报告；2）补充原始影像或电子影像；3）整理既往同类检查、既往病史和用药情况；4）将异常项汇总为问题清单后预约相关专科医生评估。这样能减少重复沟通，也便于医生更准确判断是否需要复查或进一步检查。'),
    ('体检套餐选择','warm','体检不用一开始就选最贵的，也不用担心选错。我们可以先把您家人的年龄、既往体检、家族史和最担心的问题梳理一下，再决定哪些是基础必做，哪些是建议加项。这样既不会漏掉重点，也能避免做太多没必要的项目。'),
    ('体检套餐选择','balanced','体检不是越贵越好，也不是项目越多越好。更稳妥的方式是先做基础项目，再根据年龄、家族史、既往报告和您最担心的问题来决定加项。我可以先帮您把基础项、建议加项和暂不优先项目分开，这样选择会更清楚。'),
    ('体检套餐选择','professional','建议按“基础项目 + 风险加项”的方式配置体检。请先确认年龄、性别、家族史、既往异常、慢病史和预算范围。我会把项目分为基础必选、建议加项和暂不优先三类，再根据客户风险解释每个加项的必要性。'),
    ('保险健康权益使用','warm','这件事不一定只能自己去找医院处理，您保单里可能已经有一些健康服务权益可以帮上忙。我们可以先看看现在这个情况适合用问诊、体检、绿通、二次意见还是陪诊服务。我帮您把能用的权益和需要准备的资料先整理出来，后面安排起来会轻松很多。'),
    ('保险健康权益使用','balanced','您这次的情况，可能不只是看医院资源，也可以先看看保单里已有的健康服务权益是否能用。比如问诊、体检、绿通、二次意见或陪诊服务，适合不同阶段。我可以先帮您把当前问题和可用权益对应起来，再看哪一项最适合现在启动。'),
    ('保险健康权益使用','professional','建议先核对保单或会员权益清单，再按当前健康事件匹配使用路径。请提供权益说明、客户当前问题、既往报告、就医城市和是否涉及直付/理赔。我会先判断可用权益属于问诊、体检、绿通、二诊、陪诊还是康复支持，并整理申请或预约步骤。'),
    ('港深就医路径选择','warm','先不用急着决定去哪里看，我们可以一步步判断。不同路径各有适合的情况，关键是看问题紧不紧急、手上资料是否完整、保险有没有指定安排，以及您更看重效率、费用还是连续跟进。我先帮您把这些因素整理清楚，再一起看哪条路径最合适。'),
    ('港深就医路径选择','balanced','这个问题可以先不急着决定去哪里看，我们先看三件事：第一，问题是否紧急；第二，您手上有没有完整报告和影像；第三，保险或直付路径有没有限制。香港、深圳私立和内地公立各有适合场景，我可以先帮您把资料和路径差异整理清楚。'),
    ('港深就医路径选择','professional','建议先按五个维度判断就医路径：紧急程度、已有资料、保险/直付限制、预算与时间、语言和陪诊需求。资料齐全后，可分别评估香港、深圳私立和内地公立路径的适配度，再确定预约方向。'),
    ('企业主年度健康计划','warm','您平时工作节奏很快，健康安排反而更需要做得简单、连续、少打扰。我们可以先不把体检做复杂，而是把今年最需要关注的风险列出来，再安排一套高效的检查和医生解读，后面每年都能持续比较变化。'),
    ('企业主年度健康计划','balanced','对企业主来说，体检不只是查项目，而是管理长期健康风险和家庭责任。我们可以把今年的安排做成一份年度健康资产表：先识别重点风险，再安排高效体检和医生解读，后续每年都能比较趋势。'),
    ('企业主年度健康计划','professional','建议将年度健康安排拆成四步：风险识别、体检配置、医生解读、年度复盘。重点关注心脑血管、代谢、肿瘤筛查、睡眠压力和家族史，并将检查结果沉淀为可持续更新的健康档案。'),
    ('父母健康关怀','warm','父母健康这件事，很多时候不是一次体检就能解决，而是需要有人帮忙持续记录和提醒。我们可以先从最基础的信息开始：年龄、慢病、用药、过往体检和最近有没有不舒服。先把这些整理清楚，今年该重点关注什么就会更明确。'),
    ('父母健康关怀','balanced','很多家庭真正容易忽略的，是父母每年的健康变化没有连续记录。我们可以先不急着做很复杂的安排，先把父母年龄、慢病、用药和过往体检结果整理出来，再看今年最需要关注哪些检查和复查。'),
    ('父母健康关怀','professional','建议先建立父母健康档案，包含年龄、慢病史、用药清单、既往体检、家族史和近期症状。之后按年度体检、慢病复查、癌筛加项和专科评估四类安排后续动作。'),
    ('术后/病后复查','warm','恢复期最重要的是按医生节奏来，不用自己硬扛，也不用因为感觉好一点就忽略复查。您可以先把出院小结、用药清单和复查建议发我，我帮您整理成一个时间表，后面每一步就会更安心。'),
    ('术后/病后复查','balanced','术后或病后最重要的是按医生建议复查，不要因为感觉好一些就中断跟进。您可以先把出院小结、用药清单和复查建议发我，我帮您整理成一个复查时间表，也看看是否有康复、护理或理赔相关权益可以配合使用。'),
    ('术后/病后复查','professional','建议先整理出院小结、手术/治疗记录、复查建议、用药清单和近期症状变化，再按医生要求建立复查时间表。如有康复、护理、营养或理赔相关权益，可同步确认使用路径。')
) as s(title, tone, template)
on s.title = e.title;
